 37	   * 2^sn_field_length (which is 'sn_modulus' in rlc_entity_um_t)
 38	   */
 39	  int r = a - (entity->vr_uh - entity->window_size);
 40	  if (r < 0) r += entity->sn_modulus;
 41	  return r % entity->sn_modulus;
 42	}
