    }
    r->sdu[r->sdu_pos] = pdu->data[data_pos];
    r->sdu_pos++;
    data_pos++;
    if (data_pos == sdu_offset + sdu_len) {
      /* all bytes of SDU are consumed, check if SDU is fully there.
       * It is if the data pointer is not at the end of the PDU segment
       * or if 'fi' & 1 == 0
