                                     r->sdu, r->sdu_pos);
        }
        r->sdu_pos = 0;
      }
      /* done with PDU? */
      if (data_pos == pdu->size)
        break;
      /* not at the end of PDU, process next SDU */
      sdu_offset += sdu_len;
      if (e) {
        e       = rlc_pdu_decoder_get_bits(&r->dec, 1);
        sdu_len = rlc_pdu_decoder_get_bits(&r->dec, 11);
      } else
        sdu_len = pdu->size - sdu_offset;
    }
  }
